from autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchclass McpConfig:    @staticmethod    def get_mysql_workbench():        mysql_server_params = StdioServerParams(            command="/Users/srisatyakalyankallepalli/mcp-env/bin/python",            args=["-m", "mcp_server_mysql"],            env={                "MYSQL_HOST": "127.0.0.1",                "MYSQL_PORT": "3306",                "MYSQL_USER": "root",                "MYSQL_PASSWORD": "password",                "MYSQL_DATABASE": "rahulshettyacademy",            },        )        return McpWorkbench(server_params=mysql_server_params)    @staticmethod    def get_rest_api_workbench():        rest_api_params = StdioServerParams(            command="npx",            args=["-y", "dkmaker-mcp-rest-api"],            env={                "REST_BASE_URL": "https://rahulshettyacademy.com",                "HEADER_Accept": "application/json",            },        )        return McpWorkbench(server_params=rest_api_params)    @staticmethod    def get_fs_workbench():        fs_workbench_params = StdioServerParams(            command="npx",            args=[                "-y",                "@modelcontextprotocol/server-filesystem",                "/Users/srisatyakalyankallepalli/Documents/claude_files",            ],            env={},        )        return McpWorkbench(server_params=fs_workbench_params)    @staticmethod    def get_excel_workbench():        excel_workbench_params = StdioServerParams(            command="npx",            args=["--yes", "@negokaz/excel-mcp-server"],            env={"EXCEL_MCP_PAGING_CELLS_LIMIT": "4000"},        )        return McpWorkbench(server_params=excel_workbench_params)